namespace UniversityCourseCatalog.Models;

public class Course
{
    public int Id { get; set; }
    public string CourseCode { get; set; } = string.Empty;
    public string Title { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public int Credits { get; set; }
    public string Schedule { get; set; } = string.Empty;
    public string InstructorName { get; set; } = string.Empty;
    public string InstructorBio { get; set; } = string.Empty;
    public string DepartmentId { get; set; } = string.Empty;
    public bool IsFeatured { get; set; }
}

public class Department
{
    public string Id { get; set; } = string.Empty;
    public string Name { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
}

public class EnrollmentRequest
{
    public string StudentName { get; set; } = string.Empty;
    public string StudentId { get; set; } = string.Empty;
    public int CourseId { get; set; }
}

using UniversityCourseCatalog.Models;

namespace UniversityCourseCatalog.Services;

public class CatalogService
{
    private readonly List<Department> _departments =
    [
        new() { Id = "cs", Name = "Computer Science", Description = "Study of computation, algorithms, and information systems." },
        new() { Id = "math", Name = "Mathematics", Description = "Pure and applied mathematics, statistics, and data analysis." },
        new() { Id = "eng", Name = "English", Description = "Literature, writing, and communication studies." },
        new() { Id = "phys", Name = "Physics", Description = "Study of matter, energy, and fundamental forces of nature." },
        new() { Id = "hist", Name = "History", Description = "Examination of past events, societies, and civilizations." },
    ];

    private readonly List<Course> _courses =
    [
        new() { Id = 1, CourseCode = "CS 101", Title = "Introduction to Programming", Description = "Fundamentals of programming using Python. Covers variables, control flow, functions, and basic data structures.", Credits = 3, Schedule = "Mon/Wed/Fri 9:00–9:50 AM", InstructorName = "Dr. Sarah Chen", InstructorBio = "Ph.D. in Computer Science from MIT. 12 years of teaching experience specializing in introductory programming and software engineering.", DepartmentId = "cs", IsFeatured = true },
        new() { Id = 2, CourseCode = "CS 201", Title = "Data Structures and Algorithms", Description = "Study of fundamental data structures (trees, graphs, hash tables) and algorithm design techniques including divide-and-conquer, dynamic programming, and greedy algorithms.", Credits = 4, Schedule = "Tue/Thu 10:30 AM–12:00 PM", InstructorName = "Dr. James Rodriguez", InstructorBio = "Former software engineer at Google. Research interests in algorithm optimization and competitive programming.", DepartmentId = "cs", IsFeatured = true },
        new() { Id = 3, CourseCode = "CS 310", Title = "Database Systems", Description = "Relational database design, SQL, normalization, transaction processing, and introduction to NoSQL databases.", Credits = 3, Schedule = "Mon/Wed 2:00–3:15 PM", InstructorName = "Dr. Sarah Chen", InstructorBio = "Ph.D. in Computer Science from MIT. 12 years of teaching experience specializing in introductory programming and software engineering.", DepartmentId = "cs", IsFeatured = false },
        new() { Id = 4, CourseCode = "MATH 151", Title = "Calculus I", Description = "Limits, derivatives, and integrals of single-variable functions. Applications to physics and engineering problems.", Credits = 4, Schedule = "Mon/Wed/Fri 10:00–10:50 AM", InstructorName = "Dr. Emily Watson", InstructorBio = "Specialist in applied mathematics with publications in numerical analysis. Award-winning educator.", DepartmentId = "math", IsFeatured = true },
        new() { Id = 5, CourseCode = "MATH 250", Title = "Linear Algebra", Description = "Vector spaces, linear transformations, matrices, determinants, eigenvalues, and applications to data science.", Credits = 3, Schedule = "Tue/Thu 1:00–2:15 PM", InstructorName = "Dr. Emily Watson", InstructorBio = "Specialist in applied mathematics with publications in numerical analysis. Award-winning educator.", DepartmentId = "math", IsFeatured = false },
        new() { Id = 6, CourseCode = "MATH 320", Title = "Probability and Statistics", Description = "Probability theory, random variables, distributions, hypothesis testing, and regression analysis.", Credits = 3, Schedule = "Mon/Wed/Fri 11:00–11:50 AM", InstructorName = "Dr. Michael Park", InstructorBio = "Statistician with industry experience in biotech. Focuses on making statistics accessible and practical.", DepartmentId = "math", IsFeatured = false },
        new() { Id = 7, CourseCode = "ENG 110", Title = "Academic Writing", Description = "Developing clear, persuasive academic prose. Emphasis on argumentation, research methods, and revision strategies.", Credits = 3, Schedule = "Tue/Thu 9:00–10:15 AM", InstructorName = "Prof. Linda Okafor", InstructorBio = "Published author and writing consultant. MFA from the Iowa Writers' Workshop.", DepartmentId = "eng", IsFeatured = false },
        new() { Id = 8, CourseCode = "ENG 225", Title = "American Literature", Description = "Survey of American literary works from the colonial period to the present, examining themes of identity, freedom, and innovation.", Credits = 3, Schedule = "Mon/Wed 3:30–4:45 PM", InstructorName = "Prof. Linda Okafor", InstructorBio = "Published author and writing consultant. MFA from the Iowa Writers' Workshop.", DepartmentId = "eng", IsFeatured = true },
        new() { Id = 9, CourseCode = "PHYS 101", Title = "General Physics I", Description = "Mechanics, thermodynamics, and waves. Calculus-based approach with weekly laboratory sessions.", Credits = 4, Schedule = "Mon/Wed/Fri 1:00–1:50 PM + Lab Thu 2:00–4:00 PM", InstructorName = "Dr. Robert Kim", InstructorBio = "Experimental physicist with research in quantum optics. Passionate about hands-on laboratory education.", DepartmentId = "phys", IsFeatured = false },
        new() { Id = 10, CourseCode = "PHYS 205", Title = "Modern Physics", Description = "Special relativity, quantum mechanics, atomic and nuclear physics. Bridges classical and modern understanding.", Credits = 3, Schedule = "Tue/Thu 11:00 AM–12:15 PM", InstructorName = "Dr. Robert Kim", InstructorBio = "Experimental physicist with research in quantum optics. Passionate about hands-on laboratory education.", DepartmentId = "phys", IsFeatured = false },
        new() { Id = 11, CourseCode = "HIST 101", Title = "World History to 1500", Description = "Survey of major civilizations, trade networks, and cultural exchanges from prehistory through the medieval period.", Credits = 3, Schedule = "Tue/Thu 2:30–3:45 PM", InstructorName = "Dr. Anna Petrova", InstructorBio = "Historian specializing in cross-cultural exchanges. Author of three books on medieval trade routes.", DepartmentId = "hist", IsFeatured = false },
        new() { Id = 12, CourseCode = "HIST 240", Title = "The Modern Era", Description = "Political, social, and economic transformations from the Enlightenment through the 21st century.", Credits = 3, Schedule = "Mon/Wed 10:00–11:15 AM", InstructorName = "Dr. Anna Petrova", InstructorBio = "Historian specializing in cross-cultural exchanges. Author of three books on medieval trade routes.", DepartmentId = "hist", IsFeatured = true },
    ];

    public List<Department> GetDepartments() => _departments;

    public Department? GetDepartment(string id) => _departments.FirstOrDefault(d => d.Id == id);

    public List<Course> GetAllCourses() => _courses;

    public List<Course> GetFeaturedCourses() => _courses.Where(c => c.IsFeatured).ToList();

    public List<Course> GetCoursesByDepartment(string departmentId) =>
        _courses.Where(c => c.DepartmentId == departmentId).ToList();

    public Course? GetCourse(int id) => _courses.FirstOrDefault(c => c.Id == id);

    public List<Course> SearchCourses(string? searchTerm, string? departmentFilter)
    {
        var query = _courses.AsEnumerable();

        if (!string.IsNullOrWhiteSpace(departmentFilter))
            query = query.Where(c => c.DepartmentId == departmentFilter);

        if (!string.IsNullOrWhiteSpace(searchTerm))
        {
            var term = searchTerm.ToLowerInvariant();
            query = query.Where(c =>
                c.Title.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.CourseCode.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.InstructorName.Contains(term, StringComparison.OrdinalIgnoreCase));
        }

        return query.ToList();
    }

    public bool SubmitEnrollmentRequest(EnrollmentRequest request)
    {
        // In a real app, this would persist to a database
        return !string.IsNullOrWhiteSpace(request.StudentName)
            && !string.IsNullOrWhiteSpace(request.StudentId)
            && request.CourseId > 0
            && _courses.Any(c => c.Id == request.CourseId);
    }
}

