@page "/courses"
@using UniversityCourseCatalog.Services
@using UniversityCourseCatalog.Models
@rendermode InteractiveServer
@inject CatalogService Catalog

<PageTitle>Course Catalog</PageTitle>

<h1>Course Catalog</h1>

<div class="row mb-3">
    <div class="col-md-6">
        <input type="text" class="form-control" placeholder="Search by title, code, or instructor..."
               @bind="searchTerm" @bind:event="oninput" />
    </div>
    <div class="col-md-4">
        <select class="form-select" @bind="departmentFilter">
            <option value="">All Departments</option>
            @foreach (var dept in Catalog.GetDepartments())
            {
                <option value="@dept.Id">@dept.Name</option>
            }
        </select>
    </div>
</div>

<table class="table table-striped">
    <thead>
        <tr>
            <th>Code</th>
            <th>Title</th>
            <th>Credits</th>
            <th>Instructor</th>
            <th></th>
        </tr>
    </thead>
    <tbody>
        @foreach (var course in FilteredCourses)
        {
            <tr>
                <td>@course.CourseCode</td>
                <td>@course.Title</td>
                <td>@course.Credits</td>
                <td>@course.InstructorName</td>
                <td><a href="courses/@course.Id" class="btn btn-sm btn-outline-primary">Details</a></td>
            </tr>
        }
    </tbody>
</table>

@if (!FilteredCourses.Any())
{
    <p class="text-muted">No courses match your search criteria.</p>
}

@code {
    private string searchTerm = string.Empty;
    private string departmentFilter = string.Empty;

    private List<Course> FilteredCourses => Catalog.SearchCourses(searchTerm, departmentFilter);
}

@page "/courses/{Id:int}"
@using UniversityCourseCatalog.Services
@using UniversityCourseCatalog.Models
@inject CatalogService Catalog

<PageTitle>@(course?.Title ?? "Course Not Found")</PageTitle>

@if (course is null)
{
    <h1>Course Not Found</h1>
    <p>The requested course does not exist.</p>
    <a href="courses" class="btn btn-secondary">Back to Catalog</a>
}
else
{
    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="courses">Courses</a></li>
            <li class="breadcrumb-item"><a href="departments/@course.DepartmentId">@department?.Name</a></li>
            <li class="breadcrumb-item active">@course.CourseCode</li>
        </ol>
    </nav>

    <h1>@course.CourseCode &mdash; @course.Title</h1>

    <div class="row mt-4">
        <div class="col-md-8">
            <h4>Description</h4>
            <p>@course.Description</p>

            <h4 class="mt-3">Schedule</h4>
            <p>@course.Schedule</p>

            <h4 class="mt-3">Credits</h4>
            <p><span class="badge bg-primary fs-6">@course.Credits credits</span></p>
        </div>
        <div class="col-md-4">
            <div class="card">
                <div class="card-body">
                    <h5 class="card-title">Instructor</h5>
                    <h6 class="card-subtitle mb-2">@course.InstructorName</h6>
                    <p class="card-text">@course.InstructorBio</p>
                </div>
            </div>

            <div class="mt-3">
                <a href="enroll?courseId=@course.Id" class="btn btn-success w-100">Enroll in This Course</a>
            </div>
        </div>
    </div>
}

@code {
    [Parameter] public int Id { get; set; }

    private Course? course;
    private Department? department;

    protected override void OnInitialized()
    {
        course = Catalog.GetCourse(Id);
        if (course is not null)
            department = Catalog.GetDepartment(course.DepartmentId);
    }
}

