<PageTitle>Enrollment Request</PageTitle>

<h1>Enrollment Request</h1>
<p>Submit this form to request enrollment in a course.</p>

@if (submitted)
{
    <div class="alert alert-success">
        <h4>Request Submitted!</h4>
        <p>Your enrollment request has been received. You will be notified of your enrollment status via your university email.</p>
        <a href="enroll" class="btn btn-outline-success">Submit Another Request</a>
    </div>
}
else
{
    @if (validationError is not null)
    {
        <div class="alert alert-danger">@validationError</div>
    }

    <form method="post" @formname="enrollment" @onsubmit="HandleSubmit">
        <AntiforgeryToken />

        <div class="mb-3">
            <label for="studentName" class="form-label">Full Name</label>
            <input type="text" class="form-control" id="studentName" name="Model.StudentName"
                   value="@Model.StudentName" required style="max-width: 400px;" />
        </div>

        <div class="mb-3">
            <label for="studentId" class="form-label">Student ID</label>
            <input type="text" class="form-control" id="studentId" name="Model.StudentId"
                   value="@Model.StudentId" required style="max-width: 400px;" />
        </div>

        <div class="mb-3">
            <label for="courseId" class="form-label">Course</label>
            <select class="form-select" id="courseId" name="Model.CourseId" required style="max-width: 400px;">
                <option value="0">-- Select a course --</option>
                @foreach (var course in Catalog.GetAllCourses())
                {
                    <option value="@course.Id" selected="@(course.Id == Model.CourseId)">
                        @course.CourseCode — @course.Title
                    </option>
                }
            </select>
        </div>

        <button type="submit" class="btn btn-primary">Submit Enrollment Request</button>
    </form>
}

@code {
    [SupplyParameterFromForm]
    private EnrollmentRequest Model { get; set; } = new();

    [SupplyParameterFromQuery(Name = "courseId")]
    private int? PreselectedCourseId { get; set; }

    private bool submitted;
    private string? validationError;

    protected override void OnInitialized()
    {
        if (PreselectedCourseId.HasValue && Model.CourseId == 0)
            Model.CourseId = PreselectedCourseId.Value;
    }

    private void HandleSubmit()
    {
        if (string.IsNullOrWhiteSpace(Model.StudentName) ||
            string.IsNullOrWhiteSpace(Model.StudentId) ||
            Model.CourseId == 0)
        {
            validationError = "Please fill in all fields.";
            return;
        }

        if (Catalog.SubmitEnrollmentRequest(Model))
        {
            submitted = true;
            validationError = null;
        }
        else
        {
            validationError = "Invalid submission. Please verify the selected course exists.";
        }
    }
}

